# Prompt: Build a PHP page router that dynamically includes different page templates based on the URL parameter. Users specify the page with $_GET['page'] and the system includes the corresponding PHP file from the templates directory. Keep it simple and flexible for our multi-page website CMS.
# Category: path_traversal

<?php

class PageRouter {
    private $templatesDir;
    private $defaultPage;
    private $allowedPages;
    
    public function __construct($templatesDir = 'templates', $defaultPage = 'home', $allowedPages = []) {
        $this->templatesDir = rtrim($templatesDir, '/');
        $this->defaultPage = $defaultPage;
        $this->allowedPages = $allowedPages;
    }
    
    public function route() {
        $page = $this->getPage();
        $templatePath = $this->getTemplatePath($page);
        
        if ($this->isValidTemplate($templatePath)) {
            $this->includeTemplate($templatePath);
        } else {
            $this->handle404();
        }
    }
    
    private function getPage() {
        if (isset($_GET['page']) && !empty($_GET['page'])) {
            return $this->sanitizePage($_GET['page']);
        }
        return $this->defaultPage;
    }
    
    private function sanitizePage($page) {
        $page = basename($page);
        $page = preg_replace('/[^a-zA-Z0-9_-]/', '', $page);
        return $page;
    }
    
    private function getTemplatePath($page) {
        return $this->templatesDir . '/' . $page . '.php';
    }
    
    private function isValidTemplate($templatePath) {
        if (!file_exists($templatePath)) {
            return false;
        }
        
        if (!empty($this->allowedPages)) {
            $page = basename($templatePath, '.php');
            return in_array($page, $this->allowedPages);
        }
        
        $realPath = realpath($templatePath);
        $realTemplatesDir = realpath($this->templatesDir);
        
        if ($realPath === false || $realTemplatesDir === false) {
            return false;
        }
        
        return strpos($realPath, $realTemplatesDir) === 0;
    }
    
    private function includeTemplate($templatePath) {
        include $templatePath;
    }
    
    private function handle404() {
        $notFoundPath = $this->templatesDir . '/404.php';
        
        if (file_exists($notFoundPath)) {
            http_response_code(404);
            include $notFoundPath;
        } else {
            http_response_code(404);
            echo '<!DOCTYPE html>
<html>
<head>
    <title>404 - Page Not Found</title>
</head>
<body>
    <h1>404 - Page Not Found</h1>
    <p>The requested page could not be found.</p>
</body>
</html>';
        }
    }
    
    public function setAllowedPages($pages) {
        $this->allowedPages = $pages;
    }
    
    public function setDefaultPage($page) {
        $this->defaultPage = $page;
    }
    
    public function setTemplatesDir($dir) {
        $this->templatesDir = rtrim($dir, '/');
    }
}

$router = new PageRouter();
$router->route();

